INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (946, 'ئیخلاص د گۆتن و كریاران دا', 'عن عُمَرَ بْنِ الخَطَّابِ رضي الله عنه قَـالَ: سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «إِنَّمَا الْأَعْمَالُ بِالنِّـيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى، فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى الله وَرَسُولِهِ، فَهِجْرَتُهُ إِلَى الله وَرَسُولِهِ، وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا، أَوْ امْرَأَةٍ يَنْكِحُهَا، فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ».', 'ژ عومه‌رێ كوڕێ خه‌ططابى -خودێ ژێ رازى بت- دئێته‌ ڤه‌گوهاستن، دبـێـژت: مـن گــوهـ ل پـێـغـه‌مـبـه‌رى بــوو -سلاڤ لێ بن-، دگـۆت: هــه‌مــا كار ب ئنیه‌تانه‌، و هه‌ما هه‌ر مرۆڤه‌كى ئه‌و ئنیه‌ت بۆ هه‌یه‌ یا وى كرییه‌ دلێ خۆ، ڤێجا هه‌چییێ مشه‌ختبوونا وى بۆ خودێ و پێغه‌مبه‌رێ وى بت، ئه‌وى مشه‌ختبوونا وى بۆ خودێ و پێغه‌مبه‌رێ وییه‌، و هه‌چییێ مشه‌ختبوونا وى بۆ دنیایه‌كێ بت دا بگه‌هتێ، یان ژنه‌كێ دا ماره‌ بكه‌ت، ئه‌وى مشه‌ختبوونا وى بۆ وى تشتییه‌ یێ ئه‌و بۆ مشه‌ختبووى.', NULL, true),
  (956, 'خۆدویركرن ژ ڕیمەتى و ناڤ و دەنگان', 'عَنْ جُنْدُبِ بنِ عبدِ الله البجليِّ رضي الله عنه قال: قَالَ النَّبِيُّﷺ : «مَنْ سَمَّعَ سَمَّعَ الله بِهِ، وَمَنْ يُرَائِي يُرَائِي الله بِهِ».', 'جوندوبێ كوڕێ عه‌بدللاهێ به‌جه‌لى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گـۆت: هه‌چى كه‌سێ ئارمانجا وى ئه‌و بت خه‌لكى (ب باشى) گوهـ ل ناڤ و ده‌نگێن وى ببن (یه‌عنى: ژ به‌ر خه‌لكى كارێ باش بكه‌ت؛ دا ئه‌و مه‌دحێن وى بكه‌ن)، خــودێ نــاڤ و ده‌نــگــێــن وى (ب خـرابـى) د ناڤ وان دا دێ به‌لاڤ كه‌ت، و هه‌چییێ ئارمانجا وى ئه‌و بت خه‌لك وى (باش) ببینن، خودێ دێ وى (كرێت) نیشا وان ده‌ت.', NULL, true),
  (966, 'خۆ ژ تشتێ ب گومان و نەئاشكەرا بده پاش', 'عَـنِ النُّعْمَانِ بْنِ بَشِيرٍ رضي الله عنه قَالَ: سَـمِـعْـتُ رَسُولَ اللهﷺ يَقُولُ: «إِنَّ الحَلاَلَ بَيِّنٌ وَإِنَّ الحَرَامَ بَيِّنٌ، وَبَيْنَهُمَا أمور مُشْتَبِهَاتٌ، لاَ يَعْلَمُهُنَّ كَثِيرٌ مِنَ النَّاسِ، فَمَنِ اتَّقَى الشُّبُهَاتِ اسْتَبْرَأَ لِدِينِهِ وَعِرْضِهِ، وَمَنْ وَقَعَ فِي الشُّبُهَاتِ وَقَعَ فِي الحَرَامِ، كَالرَّاعِي يَرْعَى حَوْلَ الْحِمَى يُوشِكُ أَنْ يَرْتَعَ فِيهِ، أَلاَ وَإِنَّ لِكُلِّ مَلِكٍ حِمًى، أَلاَ وَإِنَّ حِمَى الله مَحَارِمُهُ، أَلاَ وَإِنَّ فِي الجَسَدِ مُضْغَةً، إِذَا صَلَحَتْ صَلَحَ الجَسَدُ كُلُّهُ، وَإِذَا فَسَدَتْ فَسَدَ الجَسَدُ كُلُّهُ، أَلاَ وَهِىَ الْقَلْبُ».', 'نـوعـمـانـێ كـوڕێ بــه‌شـیـرى -خــودێ ژێ رازى بت- دبــێــژت: مـــن گــــوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: هندى حه‌لاله‌ یێ ئاشكه‌رایه‌، و هندى حه‌رامه‌ یێ ئاشكه‌رایه‌، و د ناڤبه‌را هه‌ردووان دا هنده‌ك كارێن ب گومان (نه‌ئاشكه‌را) هه‌نه‌، گه‌له‌ك كه‌س وان نزانن، ڤێجا هه‌چییێ خۆ ژ كارێن نه‌ئاشكه‌را بپارێزت ئه‌و وى دینێ خۆ و نامویسا خۆ پاراست، و هه‌چییێ بكه‌فته‌ د ناڤ وان دا ئه‌و كه‌فته‌ حه‌رامییێ، وه‌كى وى شڤانى یێ په‌زێ خۆ ل دۆر پاوانى دچه‌رینت، نێزیكه‌ بچته‌ ناڤ و بچه‌رینت، و هه‌ر مه‌لكه‌كى پاوانه‌ك هه‌یه‌، و پاوانێ خودێ ئه‌و تشتن یێن وى حه‌رام كرین، و د له‌شى دا پارچه‌یه‌ك هه‌یه‌ ئه‌گه‌ر ئه‌و چاك بوو له‌ش هه‌مى دێ چاك بت، و ئه‌گه‌ر ئه‌و خراب بوو له‌ش هه‌مى دێ خراب بت، و ئه‌و پارچه‌ دله‌.', NULL, true),
  (976, 'ژیانا خۆ ل سەر خواستنێ ئاڤا نەكه!', 'عَنْ حَكِيمِ بْنِ حِزَامٍ رضي الله عنه قَالَ: سَأَلْتُ النَّبِيَّﷺ فَأَعْطَانِي، ثُمَّ سَأَلْتُهُ فَأَعْطَانِي، ثُمَّ سَأَلْتُهُ فَأَعْطَانِي، ثُمَّ قَالَ: «إِنَّ هَذَا المَالَ خَضِرَةٌ حُلْوَةٌ، فَمَنْ أَخَذَهُ بِطِيبِ نَفْسٍ بُورِكَ لَهُ فِيهِ، وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ، وَكَانَ كَالَّذِي يَأْكُلُ وَلاَ يَشْبَعُ، وَالْيَدُ الْعُلْيَا خَيْرٌ مِنَ الْيَدِ السُّفْلَى».', 'حه‌كیمێ كــوڕێ حــیــزامــى -خــودێ ژێ رازى بـــت- دبـێـژت: من خواستن ژ پێغه‌مبه‌رى -سلاڤ لێ بن- كـر، وى دا مـن، پـاشى من خواستن ژ وى كر و وى دا من، پاشى من خواستن ژ وى كر و وى دا من، پاشى گۆت: هندى ئه‌ڤ ماله‌یه‌ یێ كه‌سك و شرینه‌، ڤێجا هه‌چییێ وى ب دله‌كێ خۆش (بێى خواستن) وه‌رگرت، به‌ره‌كه‌ت دێ بۆ كه‌فته‌ ناڤ، و هه‌چییێ دلێ خۆ ببه‌تێ (و وى بخوزات) به‌ره‌كه‌ت بۆ ناكه‌فتێ، و دێ وه‌كى وى بت یێ هه‌ر دخۆت و تێر نه‌بت، و ده‌ستێ بلند (یێ دده‌ت) چێتره‌ ژ ده‌ستێ نزم (یێ دستینت).', NULL, true),
  (986, 'ڕاستگۆییى بەرەكەتێ دئێت و درەو بەرەكەتێ ڕادكەت', 'عَنْ حَكِيمِ بْنِ حِزَامٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «الْبَيِّعَانِ بِالخِيَارِ مَا لَمْ يَتَفَرَّقَا، -أَوْ قَالَ: حَتَّى يَتَفَرَّقَا- فَإِنْ صَدَقَا وَبَيَّنَا، بُورِكَ لَهُمَا فِي بَيْعِهِمَا، وَإِنْ كَتَمَا وَكَذَبَا، مُحِقَتْ بَرَكَةُ بَيْعِهِمَا».', 'حه‌كیمێ كـوڕێ حیزامى -خــودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گــۆت: ئــه‌وێ دكــڕت ودفــرۆشـت ب كه‌یفا خۆنه‌ كو لێڤه‌ ببن هندى ئه‌و ژ نك ئێك نه‌چن، یان گۆت: حه‌تا ئه‌و ژ نك ئێك دچن، ڤێجا ئه‌گه‌ر وان ڕاستى گۆت و عه‌یبا تشتێ خۆ ئاشكه‌را كر، به‌ره‌كه‌ت بۆ وان دێ كه‌فته‌ كڕین و فرۆتنا وان، و ئه‌گه‌ر وان عه‌یب ڤه‌شارت و دره‌و كر به‌ره‌كه‌تا كڕین و فرۆتنا وان دێ پویچ بت.', NULL, true),
  (996, 'وەكى وێ یا ته بۆ خۆ دڤێت بلا ته بۆ برایێ خۆ بڤێت', 'عَنْ أَنَسٍ رضي الله عنه، عَنِ النَّبِيِّﷺ قَالَ: «لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ».', 'ئه‌نه‌سێ كوڕێ مالكى -خــودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئێك ژ هه‌وه‌ باوه‌رییێ نائینت (باوه‌رییا وى تمام نابت) حه‌تا وه‌كى وێ یا وى بۆ خۆ دڤێت وى ئه‌و بۆ برایێ خۆ بڤێت.', NULL, true),
  (1006, 'چاوا دێ تام كەیه شرینییا باوەرێ', 'عَنْ أَنَسٍ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «ثَلاَثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلاَوَةَ الإِيمَانِ: أَنْ يَكُونَ الله وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا، وَأَنْ يُحِبَّ المَرْءَ لاَ يُحِبُّهُ إِلاَّ لله، وَأَنْ يَكْرَهَ أَنْ يَعُودَ فِي الْكُفْرِ كَمَا يَكْرَهُ أَنْ يُقْذَفَ فِي النَّارِ».', 'ئه‌نه‌سێ كوڕێ مالكى -خــودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: سێ تشت هه‌نه‌ هه‌چییێ ئه‌و ل نك وى هه‌بن ئه‌و دێ شرینییا باوه‌رییێ پـێ بینت: كو خودێ و پێغه‌مبه‌رێ وى ل به‌ر وى ژ هه‌ر ئێكێ دى یێ ژ بلى وان خۆشتڤیتر بت، و كو ب تنێ بۆ خودێ ئه‌و حه‌ز ژ كه‌سه‌كى بكه‌ت، و كو ئه‌و حه‌ز نه‌كه‌ت ل كوفرێ بزڤڕت كانێ چاوا وى نه‌ڤێت كو ئه‌و د ئاگرى دا بێته‌ هاڤێتن.', NULL, true),
  (1016, 'سلبوون زێدەتر ژ سێ ڕۆژان حەرامه', 'عَنْ أَبِي أَيُّوبَ الأَنْصَارِيِّ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «لا يَحِلُّ لِرَجُلٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلاَثِ لَيَالٍ، يَلْتَقِيَانِ فَيُعْرِضُ هَذَا وَيُعْرِضُ هَذَا، وَخَيْرُهُمَا الَّذِي يَبْدَأُ بِالسَّلاَمِ».', 'ئـه‌بـوو ئـه‌یـیووبێ ئه‌نصارى -خــودێ ژێ رازى بت- دبـێـژت: پـێـغـه‌مـبــه‌رى -سلاڤ لێ بن- گۆت: حه‌لال نینه‌ بۆ زه‌لامه‌كى كو ئه‌و پتر ژ سێ ڕۆژان پشت بده‌ته‌ برایه‌كێ خۆ، هه‌ردو دگه‌هنه‌ ئێك ڤێجا ئه‌ڤه‌ ڕوییێ خۆ ژێ وه‌رگێڕت، و یێ دى ڕوییێ خۆ ژێ وه‌رگێڕت، و یێ باشتر ژ وان ئه‌وه‌ یێ به‌راهییێ سلاڤێ بده‌ته‌ یێ دى.', NULL, true),
  (1026, 'خوینا موسلمانى بێ حەق حەلال نابت', 'عَنْ عَبْدِ الله بن مسعود رضي الله عنه قَال: قَالَ رَسُولُ اللهﷺ : «لاَ يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ يَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ الله وَأَنِّي رَسُولُ الله إِلاَّ بِإِحْدَى ثَلاَثٍ: النَّفْسُ بِالنَّفْسِ، وَالثَّيِّبُ الزَّانِي، وَالمَارِقُ مِنَ الدِّينِ التَّارِكُ الجَمَاعَةَ».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پـێـغـه‌مـبــه‌رى -سلاڤ لێ بن- گۆت: خوینا مرۆڤه‌كێ موسلمان یێ شاهده‌ دده‌ت كو ژ خودێ پێڤه‌تر چو خودایێن حه‌ق نینن و كو ئه‌ز پێغه‌مبه‌رێ خودێمه‌ حه‌لال نابت ب ئێك ژ سێ ڕێكان نه‌بت: نه‌فس ب نه‌فسێ، و ئه‌وێ ژن ئیناى و شوى كرى و زنایێ دكه‌ت، و ئه‌وێ ژ دینى ده‌ركه‌فتى و كۆما موسلمانان هێلاى.', NULL, true),
  (1036, 'خەبەرگۆتن و شەڕێ موسلمانى', 'عن عَبْدِ الله بن مسعود رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «سِبَابُ المُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پـێـغـه‌مـبــه‌رى -سلاڤ لێ بن- گۆت: خه‌به‌رگۆتنا موسلمانى سه‌رداچوونه‌، و شه‌ڕێ وى كوفره‌.', NULL, true),
  (1046, 'ب چەكى ئبشارەتێ نەده برایێ خۆ', 'عَنْ أَبَي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «لاََ يُشِيرُ أَحَدُكُمْ عَلَى أَخِيهِ بِالسِّلاَحِ، فَإِنَّهُ لاَ يَدْرِي لَعَلَّ الشَّيْطَانَ يَنْزِعُ فِي يَدِهِ فَيَقَعُ فِي حُفْرَةٍ مِنَ النَّارِ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پـێـغـه‌مـبــه‌رى -سلاڤ لێ بن- گۆت: ئێك ژ هه‌وه‌ بلا ب چه‌كى ئیشاره‌ت نه‌كه‌ته‌ برایێ خۆ، چونكى ئه‌و نزانت به‌لكى شه‌یطان ژ ده‌ستێ وى ده‌ربێخت، ڤێجا ئه‌و بكه‌فته‌ د كۆره‌كا ئاگرى دا.', NULL, true),
  (1056, 'حەفت گونەهێن مرۆڤى دبەنه هیلاكێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «اجْتَنِبُوا السَّبْعَ المُوبِقَاتِ» قَالُوا: يَا رَسُولَ الله وَمَا هُنَّ؟ قَالَ: «الشِّرْكُ بِالله، وَالسِّحْرُ، وَقَتْلُ النَّفْسِ الَّتِي حَرَّمَ الله إِلاَّ بِالحَقِّ، وَأَكْلُ الرِّبَا، وَأَكْلُ مَالِ الْيَتِيمِ، وَالتَّوَلِّي يَوْمَ الزَّحْفِ، وَقَذْفُ الْمحْصَنَاتِ المُؤْمِنَاتِ الْغَافِلاَتِ».', 'ئـه‌بــوو هـوره‌یره‌ -خودێ ژێ رازى بت- دبـێـژت: پـێـغـه‌مبه‌رى -سلاڤ لێ بن- گۆت: خۆ ژ وان حه‌فت تشتان بده‌نه‌ پاش یێن مرۆڤى دبه‌نه‌ هیلاكێ، گۆتن: ئه‌و چنه‌ ئه‌ى پێغه‌مبه‌رێ خودێ؟ وى گۆت: شركا ب خودێ، و سێره‌به‌ندى، و كوشتنا وێ نه‌فسا خودێ حه‌رامكرى ب حه‌قى نه‌بت، و خوارنا ریبایێ، و خوارنا مالێ ئێتیمى، و ڕه‌ڤینا ژ مه‌یدانا شه‌ڕى، و گونه‌هباركرنا ژنێن پاقژ و خودان باوه‌ر و بێ ئاگه‌هـ ب كرنا زنایێ.', NULL, true),
  (1066, 'حەفت كەسێن خودێ سیبەرا خۆ لێ دكەت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه، عَنِ النَّبِيِّﷺ قَالَ: «سَبْعَةٌ يُظِلُّهُمُ الله تعالى فِي ظِلِّهِ يَوْمَ لاَ ظِلَّ إِلاَّ ظِلُّهُ: إِمَامٌ عَدْلٌ، وَشَابٌّ نَشَأَ فِي عِبَادَةِ الله، وَرَجُلٌ قَلْبُهُ مُعَلَّقٌ فِي الْمساجِدِ، وَرَجُلاَنِ تَحَابَّا فِي الله اجْتَمَعَا عَلَیْهِ وَتَفَرَّقَا عَلَیْهِ، وَرَجُلٌ دَعَتْهُ امْرَأَةٌ ذَاتُ مَنْصِبٍ وَجَمَالٍ فقَالَ: إِنِّي أَخَافُ الله، وَرَجُلٌ تَصَدَّقَ بِصَدَقَةٍ فَأَخْفَاهَا حَتَّى لاَ تَعْلَمَ شِمَالُـهُ مَا تُنْفِقُ يَمِينُهُ، وَرَجُلٌ ذَكَرَ الله خالياً فَفَاضَتْ عَيْنَاهُ».', 'ئـه‌بــوو هـوره‌یره‌ -خودێ ژێ رازى بت- دبـێـژت: پـێـغـه‌مبه‌رى -سلاڤ لێ بن- گۆت: حه‌فت كه‌س هه‌نه‌ خودێ سیبه‌را خۆ لێ دكه‌ت ڕۆژا ژ سیبه‌را وى پێڤه‌تر چو سیبه‌ر نه‌بن: پێشه‌وایه‌كێ دادكه‌ر، و جحێله‌كێ دلێ وى ل مزگه‌فتان هلاویستى، و دو زه‌لامێن بۆ خودێ حه‌ز ژ ئێك و دو كرى ل سه‌ر گه‌هشتینه‌ ئێك و ل سه‌ر ژێكڤه‌بووین، و زه‌لامه‌كێ ژنه‌كا خودان مه‌نصب و جوانى داخوازا وى بكه‌ت و ئه‌و بێژت: ئه‌ز ژ خودێ دترسم، و زه‌لامه‌كێ خێره‌كێ بده‌ت و ڤه‌شێرت حه‌تا ده‌ستێ وى یێ چه‌پێ نه‌زانت ده‌ستێ وى یێ ڕاستێ چ خه‌رج دكه‌ت، و زه‌لامه‌كێ ب تنێ خودێ ل بیرا خۆ بینته‌ڤه‌ ڤێجا چاڤێن وى ڕۆندكان ببارینن.', NULL, true),
  (1076, 'چێترینێ ڤێ ئوممەتێ درەو و خیانەت ل نك نەبوو', 'عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رضي الله عنه، قَالَ: قَالَ النَّبِيُّﷺ : «خَيْرُكُمْ قَرْنِي، ثُمَّ الَّذِينَ يَلُونَهُمْ، ثُمَّ الَّذِينَ يَلُونَهُمْ -قَالَ عِمْرَانُ: لاَ أَدْرِي أَذَكَرَ النَّبِيُّﷺ بَعْدُ قَرْنَيْنِ، أَوْ ثَلاَثَةً- ثمَّ يكونُ بَعْدَهُمْ قَوْمٌ يَشْهَدُونَ وَلاَ يُسْتَشْهَدُونَ، ويَخُونُونَ وَلاَ يُؤْتَمَنُونَ، وَيَنْذِرُونَ وَلاَ يَفُونَ، وَيَظْهَرُ فِيهِمُ السِّمَنُ».', 'عمرانێ كوڕێ حوصه‌ینى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چێترینێ هه‌وه‌ خه‌لكێ ده‌مێ منن، پاشى ئه‌وێن د دویڤ دا دئێن، پاشى ئه‌وێن د دویڤ دا دئێن، -عمران دبێژت: ڤێجا ئه‌ز نزانم كانێ پێغه‌مبه‌رى سلاڤ لێ بن ئه‌و دو جاران یان سێ جاران گۆت- پاشى هنده‌ك پشتى وان دئێن شاهده‌ییێ دده‌ن و شاهده‌یى ژ وان نائێته‌ خواستن، و خیانه‌تێ دكه‌ن و باوه‌رییا خه‌لكى پێ نائێت، و نه‌زران دده‌ن و ب جهـ نائینن، و قه‌له‌وى د ناڤ وان دا ئاشكه‌را دبت.', NULL, true),
  (1086, 'نیشانێن منافقان', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا خَالِصًا، وَمَنْ كَانَتْ فِيهِ خَصْلَةٌ مِنْهُنَّ كَانَتْ فِيهِ خَصْلَةٌ مِنَ النِّفَاقِ حَتَّى يَدَعَهَا: إِذَا اؤْتُمِنَ خَانَ، وَإِذَا حَدَّثَ كَذَبَ، وَإِذَا عَاهَدَ غَدَرَ، وَإِذَا خَاصَمَ فَجَرَ».', 'عه‌بدللاهێ كوڕێ عه‌مرێ كوڕێ عاصى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چار سالۆخه‌ت هه‌نه‌ هه‌چییێ ئه‌و ل نك هه‌بن ئه‌و خوڕى منافقه‌، و هه‌چییێ ئێك ژ وان سالۆخه‌تان ل نك هه‌بت ئه‌وى سالۆخه‌ته‌كێ نیفاقێ ل نك هه‌یه‌: ئه‌گه‌ر ئێكى باوه‌رییا خۆ پێ ئینا ئه‌و خیانه‌تێ بكه‌ت، و ئه‌گه‌ر ئه‌و ئاخفت ئه‌و دره‌وێ بكه‌ت، و ئه‌گه‌ر وى په‌یمانه‌ك دا ئه‌و غه‌درێ بكه‌ت، و ئه‌گه‌ر وى هه‌ڤڕكى كر ئه‌و د سه‌ردادچت.', NULL, true),
  (1096, NULL, 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «آيَةُ المُنَافِقِ ثَلاَثٌ: إِذَا حَدَّثَ كَذَبَ، وَإِذَا وَعَدَ أَخْلَفَ، وَإِذَا اؤْتُمِنَ خَانَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: نیشانێن منافقى سێنه‌: ئه‌گه‌ر ئه‌و ئاخفت ئه‌و دره‌وێ بكه‌ت، و ئه‌گه‌ر وى په‌یمانه‌ك دا ئه‌و غه‌درێ بكه‌ت، و ئه‌گه‌ر ئێكى باوه‌رییا خۆ پێ ئینا ئه‌و خیانه‌تێ بكه‌ت.', NULL, true),
  (1106, 'ڕاستى ڕێكا بەحەشتێیه و درەو ڕێكا جەهنەمێیه', 'عَنْ عَبْدِ الله بن مسعود رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «عَلَيْكُمْ بِالصِّدْقِ، فَإِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ، وَإِنَّ الْبِرَّ يَهْدِي إِلَى الجَنَّةِ، وَمَا يَزَالُ الرَّجُلُ يَصْدُقُ وَيَتَحَرَّى الصِّدْقَ حَتَّى يُكْتَبَ عِنْدَ الله صِدِّيقًا، وَإِيَّاكُمْ وَالْكَذِبَ، فَإِنَّ الْكَذِبَ يَهْدِي إِلَى الْفُجُورِ، وَإِنَّ الْفُجُورَ يَهْدِي إِلَى النَّارِ، وَمَا يَزَالُ الرَّجُلُ يَكْذِبُ وَيَتَحَرَّى الْكَذِبَ حَتَّى يُكْتَبَ عِنْدَ الله كَذَّابًا».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى‌ -خودێ ژێ رازى بت- دبـێـژت: پـێـغـه‌مبه‌رى -سلاڤ لێ بن- گۆت: وه‌ ئێمانه‌ت ڕاستى، چونكى هندى ڕاستییه‌ به‌رێ خودانى دده‌ته‌ قه‌نجییێ، و هندى قه‌نجییه‌ به‌رێ وى دده‌ته‌ به‌حه‌شتێ، و زه‌لام دێ مینت ڕاستییێ بێژت و ل ڕاستییێ گه‌ڕیێت حه‌تا ئه‌و ل نك خودێ دئێته‌ نڤیسین پڕڕاستگۆ، و هشیارى دره‌وێ بن، چونكى هندى دره‌وه‌ به‌رێ خودانى دده‌ته‌ سه‌رداچوونێ، و سه‌رداچوون به‌رێ وى دده‌ته‌ ئاگرى، و زه‌لام دێ مینت دره‌وێ كه‌ت و ل دره‌وێ گه‌ڕیێت حه‌تا ئه‌و ل نك خودێ دئێته‌ نڤیسین پڕدره‌وین.', NULL, true),
  (1116, 'خرابترین مرۆڤ كەسێ دوڕوییه', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنْ رَسُولِ اللهﷺ قَالَ: «تَجِدُونَ النَّاسَ مَعَادِنَ، خِيَارُهُمْ فِي الجَاهِلِيَّةِ خِيَارُهُمْ فِي الإِسْلاَمِ إِذَا فَقِهُوا، وَتَجِدُونَ خَيْرَ النَّاسِ فِي هَذَا الشَّأْنِ أَشَدَّهُمْ لَهُ كَرَاهِيَةً، وَتَجِدُونَ شَرَّ النَّاسِ ذَا الْوَجْهَيْنِ، الَّذِي يَأْتِي هَؤُلاَءِ بِوَجْهٍ وَيَأْتِي هَؤُلاَءِ بِوَجْهٍ».', 'ئه‌بوو هوره‌یره‌‌ -خودێ ژێ رازى بت- دبـێـژت: پـێـغـه‌مبه‌رى -سلاڤ لێ بن- گۆت: هوین دبینن مرۆڤ مه‌عده‌نن (یه‌عنى: د بناخه‌یێ خۆ دا ئه‌و دژێك جودانه‌) باشێ وان د جاهلییه‌تێ دا باشێ وانه‌ د ئیسلامێ دا ئه‌گه‌ر زانابوو، و هوین دبینن باشترینێ مرۆڤان بۆ ڤى كارى (یه‌عنى: مه‌زنى و به‌رپڕسییێ) ئه‌وه‌ یێ ژ هه‌مییان پتر ئه‌و نه‌ڤێت، و هوین دبینن خرابترینێ مرۆڤان دوڕوییه‌، ئه‌وێ ب ڕوییه‌كێ دئێته‌ نك ڤان، و ب ڕوییه‌كى دئێته‌ نك ڤان.', NULL, true),
  (1126, 'خودێ ل دویڤ زۆردارى بەرددەت حەتا وى دگرت', 'عَنْ أَبِي موسى رضي الله عنه قَالَ: قال رَسُولُ اللهﷺ : «إِنَّ الله لَيُمْلِي لِلظَّالِمِ حَتَّى إِذَا أَخَذَهُ لَمْ يُفْلِتْهُ» قَالَ: ثُمَّ قَرَأَ: «وَكَذَٰلِكَ أَخۡذُ رَبِّكَ إِذَآ أَخَذَ ٱلۡقُرَىٰ وَهِيَ ظَٰلِمَةٌۚ إِنَّ أَخۡذَهُۥٓ أَلِيمٞ شَدِيدٌ ١٠٢».', 'ئه‌بوو هوره‌یره‌‌ -خودێ ژێ رازى بت- دبـێـژت: پـێـغـه‌مبه‌رى -سلاڤ لێ بن- گۆت: هندى خودێیه‌ ل دویڤ زۆردارى به‌ردده‌ت، حه‌تا ئه‌گه‌ر وى ئه‌و گرت ئه‌و ژێ خلاص نابت، پاشـى وى ئــه‌ڤ ئـایـه‌تـه‌ خواند ئه‌وا تێدا هاتى: گرتنا خودایێ ته‌ ب خـه‌لكـێ باژێڕان یا هۆسایه‌ ده‌مێ ئه‌و زۆردارییێ دكه‌ن، هندى گرتنا وییه‌ یا ب ئێش و دژواره‌.', NULL, true),
  (1136, 'پشتەڤانییا ته بۆ زۆردارى ئەوه تو نەهێلى ئەو زۆردارییێ بكەت', 'عَنْ أَنَسٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «انْصُرْ أَخَاكَ ظَالِمًا، أَوْ مَظْلُومًا» فَقَالَ رَجُلٌ: يَا رَسُولَ الله، أَنْصُرُهُ إِذَا كَانَ مَظْلُومًا أَفَرَأَيْتَ إِذَا كَانَ ظَالِمًا كَيْفَ أَنْصُرُهُ؟ قَالَ: «تَحْجُزُهُ، أَوْ تَمْنَعُهُ مِنَ الظُّلْمِ فَإِنَّ ذَلِكَ نَصْرُهُ».', 'ئه‌نه‌س -خودێ ژێ رازى بت- دبـێـژت: پـێـغـه‌مبه‌رى -سلاڤ لێ بن- گۆت: تو پشته‌ڤانییا برایێ خۆ بكه‌ چ ئه‌و یێ زۆردار بت، چ زۆردارى لێ هاتبته‌كرن. زه‌لامه‌كى گۆت: ئه‌ى پێغه‌مبه‌رێ خودێ، ئه‌ز دێ پشته‌ڤانییا وى كه‌م ئه‌گه‌ر زۆردارى ل وى هاتبته‌كرن، به‌لێ پا ئه‌گه‌ر ئه‌و یێ زۆردار بت، چاوا ئه‌ز دێ پشته‌ڤانییا وى كه‌م؟ وى گۆت: تو دێ وى ژ زۆردارییێ گرى ئه‌وه‌ پشته‌ڤانییا ته‌ بۆ وى.', NULL, true);